<div class="row g-3"><div class="col-md-4"><label>Name</label><input name="name" class="form-control" value="{{ old('name',$shipmentBatch->name ?? now()->format('F Y').' Kenya Shipment') }}" required></div><div class="col-md-3"><label>Month</label><input name="month" type="date" class="form-control" value="{{ old('month', isset($shipmentBatch) ? $shipmentBatch->month->format('Y-m-d') : now()->startOfMonth()->format('Y-m-d')) }}" required></div><div class="col-md-2"><label>Status</label><input name="status" class="form-control" value="{{ old('status',$shipmentBatch->status ?? 'Open') }}" required></div><div class="col-md-3"><label>Departure date</label><input name="departure_date" type="date" class="form-control" value="{{ old('departure_date', isset($shipmentBatch) && $shipmentBatch->departure_date ? $shipmentBatch->departure_date->format('Y-m-d') : '') }}"></div><div class="col-md-3"><label>Arrival estimate</label><input name="arrival_estimate" type="date" class="form-control" value="{{ old('arrival_estimate', isset($shipmentBatch) && $shipmentBatch->arrival_estimate ? $shipmentBatch->arrival_estimate->format('Y-m-d') : '') }}"></div><div class="col-12"><label>Notes</label><textarea name="notes" class="form-control">{{ old('notes',$shipmentBatch->notes ?? '') }}</textarea></div></div>
